import type { MilestoneInfo, CompletionStatus } from "@/lib/types";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Filter value for the milestone filter bar. */
export type StatusFilter = "all" | "active" | "complete" | "planned";

/** A group of milestones sharing the same status category. */
export interface StatusGroup {
  label: string;
  status: CompletionStatus[];
  milestones: MilestoneInfo[];
}

// ---------------------------------------------------------------------------
// Category definitions
// ---------------------------------------------------------------------------

interface CategoryDef {
  label: string;
  status: CompletionStatus[];
}

const categories: CategoryDef[] = [
  { label: "Active", status: ["in-progress"] },
  { label: "Complete", status: ["done"] },
  { label: "Planned", status: ["pending", "blocked"] },
];

const filterToStatuses: Record<StatusFilter, CompletionStatus[] | null> = {
  all: null,
  active: ["in-progress"],
  complete: ["done"],
  planned: ["pending", "blocked"],
};

// ---------------------------------------------------------------------------
// Functions
// ---------------------------------------------------------------------------

/**
 * Group milestones by status category: Active (in-progress), Complete (done),
 * and Planned (pending + blocked). Returns only non-empty groups in a stable
 * order: Active → Complete → Planned.
 */
export function groupMilestonesByStatus(
  milestones: MilestoneInfo[],
): StatusGroup[] {
  if (milestones.length === 0) return [];

  const groups: StatusGroup[] = [];

  for (const cat of categories) {
    const matched = milestones.filter((m) => cat.status.includes(m.status));
    if (matched.length > 0) {
      groups.push({
        label: cat.label,
        status: cat.status,
        milestones: matched,
      });
    }
  }

  return groups;
}

/**
 * Filter milestones by status category. Returns all milestones for 'all',
 * or the subset matching the given filter.
 */
export function filterMilestonesByStatus(
  milestones: MilestoneInfo[],
  filter: StatusFilter,
): MilestoneInfo[] {
  const statuses = filterToStatuses[filter];
  if (statuses === null) return milestones;
  return milestones.filter((m) => statuses.includes(m.status));
}

/**
 * Count milestones per filter category for badge display.
 */
export function getStatusCounts(
  milestones: MilestoneInfo[],
): Record<StatusFilter, number> {
  const counts: Record<StatusFilter, number> = {
    all: milestones.length,
    active: 0,
    complete: 0,
    planned: 0,
  };

  for (const m of milestones) {
    switch (m.status) {
      case "in-progress":
        counts.active++;
        break;
      case "done":
        counts.complete++;
        break;
      case "pending":
      case "blocked":
        counts.planned++;
        break;
    }
  }

  return counts;
}

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import type { StatusFilter } from "@/lib/milestone-filters";
import { cn } from "@/lib/utils";

const filters: { value: StatusFilter; label: string }[] = [
  { value: "all", label: "All" },
  { value: "active", label: "Active" },
  { value: "complete", label: "Complete" },
  { value: "planned", label: "Planned" },
];

interface MilestoneFilterBarProps {
  counts: Record<StatusFilter, number>;
  activeFilter: StatusFilter;
  onChange: (filter: StatusFilter) => void;
}

export function MilestoneFilterBar({
  counts,
  activeFilter,
  onChange,
}: MilestoneFilterBarProps) {
  return (
    <div className="flex items-center gap-2" role="group" aria-label="Filter milestones by status">
      {filters.map(({ value, label }) => {
        const isActive = activeFilter === value;
        return (
          <Button
            key={value}
            variant={isActive ? "default" : "outline"}
            size="sm"
            data-active={isActive}
            onClick={() => onChange(value)}
            className={cn(
              "gap-1.5",
              !isActive && "text-muted-foreground",
            )}
          >
            {label}
            <Badge
              variant={isActive ? "secondary" : "outline"}
              className="ml-0.5 px-1.5 py-0 text-[10px] leading-4"
            >
              {counts[value]}
            </Badge>
          </Button>
        );
      })}
    </div>
  );
}

import { AlertCircle, Flag, FolderOpen } from "lucide-react";
import { ProgressDashboard } from "@/components/dashboard/progress-dashboard";
import { useMilestoneData } from "@/hooks/use-milestone-data";
import { useProjectStore } from "@/stores/project-store";
import { LoadingState } from "@/components/shared/loading-state";
import { EmptyState } from "@/components/shared/empty-state";

export function MilestonesPage() {
  const activeProject = useProjectStore((s) => s.activeProject);
  const { milestones, isLoading, error } = useMilestoneData();

  return (
    <div className="flex flex-col gap-6 p-6">
      <div className="flex items-center gap-3">
        <Flag className="h-6 w-6 text-primary" data-testid="page-icon" />
        <div>
          <h1 className="text-2xl font-semibold tracking-tight">Milestones</h1>
          <p className="text-sm text-muted-foreground">
            Track milestone progress and deliverables.
          </p>
        </div>
      </div>
      {!activeProject ? (
        <EmptyState
          icon={FolderOpen}
          title="No project selected"
          description="Select a project from the gallery to view milestones."
        />
      ) : isLoading ? (
        <LoadingState message="Loading milestone data…" />
      ) : error ? (
        <EmptyState
          icon={AlertCircle}
          title="Failed to load milestones"
          description={error}
        />
      ) : milestones.length === 0 ? (
        <EmptyState
          icon={Flag}
          title="No milestones"
          description="This project has no milestones yet."
        />
      ) : (
        <ProgressDashboard milestones={milestones} />
      )}
    </div>
  );
}

import { useState } from "react";
import { ChevronRight, CheckCircle2, Circle, Loader2 } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { EmptyState } from "@/components/shared/empty-state";
import { Flag } from "lucide-react";
import type { MilestoneInfo, SliceInfo, TaskInfo, CompletionStatus } from "@/lib/types";

interface ProgressDashboardProps {
  milestones: MilestoneInfo[];
}

const statusIcon: Record<CompletionStatus, React.ReactNode> = {
  done: <CheckCircle2 className="h-4 w-4 text-green-500" />,
  "in-progress": <Loader2 className="h-4 w-4 text-blue-500 animate-spin" />,
  pending: <Circle className="h-4 w-4 text-muted-foreground" />,
  blocked: <Circle className="h-4 w-4 text-red-500" />,
};

export function ProgressDashboard({ milestones }: ProgressDashboardProps) {
  if (milestones.length === 0) {
    return <EmptyState icon={Flag} title="No milestones" description="No milestone data available." />;
  }

  return (
    <div className="space-y-2">
      {milestones.map((m) => (
        <MilestoneNode key={m.id} milestone={m} />
      ))}
    </div>
  );
}

function MilestoneNode({ milestone }: { milestone: MilestoneInfo }) {
  const [expanded, setExpanded] = useState(false);

  return (
    <div className="rounded-lg border">
      <button
        type="button"
        className="flex w-full items-center gap-3 p-3 text-left hover:bg-muted/50 transition-colors"
        onClick={() => setExpanded(!expanded)}
      >
        <ChevronRight className={`h-4 w-4 shrink-0 transition-transform ${expanded ? "rotate-90" : ""}`} />
        {statusIcon[milestone.status]}
        <span className="text-sm font-medium flex-1">
          {milestone.id}: {milestone.title}
        </span>
        <span className="text-xs text-muted-foreground font-mono">${milestone.cost.toFixed(2)}</span>
        <Badge variant="outline" className="text-[10px]">{milestone.progress}%</Badge>
      </button>
      {expanded && (
        <div className="border-t px-3 pb-3">
          <div className="ml-7 mt-2 space-y-1">
            {milestone.slices.map((s) => (
              <SliceNode key={s.id} slice={s} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function SliceNode({ slice }: { slice: SliceInfo }) {
  const [expanded, setExpanded] = useState(false);

  return (
    <div>
      <button
        type="button"
        className="flex w-full items-center gap-2 rounded px-2 py-1.5 text-left hover:bg-muted/30 transition-colors"
        onClick={() => setExpanded(!expanded)}
      >
        <ChevronRight className={`h-3 w-3 shrink-0 transition-transform ${expanded ? "rotate-90" : ""}`} />
        {statusIcon[slice.status]}
        <span className="text-xs flex-1">{slice.id}: {slice.title}</span>
        <span className="text-[10px] text-muted-foreground font-mono">${slice.cost.toFixed(2)}</span>
      </button>
      {expanded && (
        <div className="ml-8 mt-1 space-y-0.5">
          {slice.tasks.map((t) => (
            <TaskNode key={t.id} task={t} />
          ))}
        </div>
      )}
    </div>
  );
}

function TaskNode({ task }: { task: TaskInfo }) {
  return (
    <div className="flex items-center gap-2 px-2 py-1 text-xs text-muted-foreground">
      {statusIcon[task.status]}
      <span className="flex-1">{task.id}: {task.title}</span>
      {task.duration && <span className="text-[10px]">{task.duration}</span>}
      <span className="font-mono text-[10px]">${task.cost.toFixed(2)}</span>
    </div>
  );
}

import { useState, useEffect, useCallback, useRef } from "react";
import { createGsdClient } from "@/services/gsd-client";
import { useProjectStore } from "@/stores/project-store";
import { deriveCostData } from "@/lib/derive-cost-data";
import type { MilestoneInfo, CostData } from "@/lib/types";

const client = createGsdClient();

interface UseMilestoneDataResult {
  milestones: MilestoneInfo[];
  costData: CostData;
  isLoading: boolean;
  error: string | null;
  refetch: () => void;
}

const emptyCostData: CostData = {
  totalCost: 0,
  budgetCeiling: null,
  byPhase: [],
  byModel: [],
  bySlice: [],
};

/**
 * Hook that fetches parsed milestone data when the active project changes.
 *
 * Subscribes to `useProjectStore.activeProject`. When it changes to a
 * non-null value, calls `parseProjectMilestones` via the GSD client
 * and derives cost data from the result.
 *
 * Returns `{ milestones, costData, isLoading, error, refetch }`.
 */
export function useMilestoneData(): UseMilestoneDataResult {
  const activeProject = useProjectStore((s) => s.activeProject);
  const [milestones, setMilestones] = useState<MilestoneInfo[]>([]);
  const [costData, setCostData] = useState<CostData>(emptyCostData);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Track the fetch generation to discard stale responses
  const fetchGenRef = useRef(0);

  const fetchData = useCallback(
    async (projectPath: string) => {
      const gen = ++fetchGenRef.current;
      setIsLoading(true);
      setError(null);

      try {
        const data = await client.parseProjectMilestones(projectPath);

        // Discard if a newer fetch has been initiated
        if (gen !== fetchGenRef.current) return;

        setMilestones(data);
        setCostData(deriveCostData(data));
      } catch (err) {
        if (gen !== fetchGenRef.current) return;

        const message = err instanceof Error ? err.message : String(err);
        setError(message);
        setMilestones([]);
        setCostData(emptyCostData);
      } finally {
        if (gen === fetchGenRef.current) {
          setIsLoading(false);
        }
      }
    },
    [],
  );

  // Fetch when activeProject changes
  useEffect(() => {
    if (!activeProject) {
      setMilestones([]);
      setCostData(emptyCostData);
      setError(null);
      setIsLoading(false);
      return;
    }

    fetchData(activeProject.path);
  }, [activeProject, fetchData]);

  const refetch = useCallback(() => {
    if (activeProject) {
      fetchData(activeProject.path);
    }
  }, [activeProject, fetchData]);

  return { milestones, costData, isLoading, error, refetch };
}

import { describe, expect, it, vi, beforeEach } from "vitest";
